import { BottomNavigation, Box, IconButton, Typography } from "@mui/material";
import InstagramIcon from "@mui/icons-material/Instagram";
import * as React from "react";
import LinkedInIcon from "@mui/icons-material/LinkedIn";
import GitHubIcon from "@mui/icons-material/GitHub";
import Stack from "@mui/material/Stack";
import { styled, createTheme } from "@mui/material/styles";
import { Animate } from "@mui/lab";

const StyledFooter = styled("footer")`
  ${({ theme }) => `
    display: flex;
    justify-content: center;
    align-items: center;
    margin-top: 16px;
    flex-direction: column;
    opacity: ${props => props.visible ? '1' : '0'}; // Initially hidden
    transform: translateX(${props => props.visible ? '0' : '-100px'}); // Initially translate -100px to the left
    transition: opacity 0.5s ease-in-out, transform 0.5s ease-in-out;
  `}
`;

export const Footer = () => {
  return (
    <Animate
      enter={{ opacity: 1, transform: "translateX(0)" }}
      leave={{ opacity: 0, transform: "translateX(-100px)" }}
      style={{
        display: "flex",
        justifyContent: "center",
        alignItems: "center",
        flexDirection: "column",
      }}
    >
      <StyledFooter>
        <Typography variant="h4">Lets Get in Touch</Typography>
        <Stack direction="row" spacing={1}>
          <IconButton sx={{ color: "#fff" }} aria-label="delete">
            <LinkedInIcon />
          </IconButton>
          <IconButton color="secondary" aria-label="add an alarm">
            <GitHubIcon />
          </IconButton>
          <IconButton color="primary" aria-label="add to shopping cart">
            <InstagramIcon />
          </IconButton>
        </Stack>
      </StyledFooter>
    </Animate>
  );
};
